const body = $json.body ?? $json;
const allowedSources = new Set(['telegram-console', 'openclaw']);
const allowedSpecialists = new Set(['product-roadmap', 'repo-architect', 'web-ui', 'server-api', 'data-migrations', 'mobile', 'hubchat-ai', 'n8n-automation', 'growth-marketing', 'qa-release', 'security']);
const allowedRiskTiers = new Set(['P0', 'P1', 'P2']);
const taskId = String(body.taskId ?? `agent-${Date.now()}`);
const source = String(body.source ?? 'telegram-console');
const action = String(body.action ?? 'plan');
const specialist = String(body.specialist ?? 'repo-architect');
const riskTier = String(body.riskTier ?? 'P2');
const mode = String(body.mode ?? 'read-only');
const commandText = String(body.commandText ?? body.intent?.rawText ?? '');
const requiresApproval = Boolean(body.requiresApproval);
const approvalId = body.approvalId ? String(body.approvalId) : undefined;
const statusCallback = body.statusCallback ?? null;
const artifacts = Array.isArray(body.artifacts) ? body.artifacts : [];

function reject(reason, nextStep) {
  return [{ json: { taskId, status: 'rejected', reason, source, action, specialist, riskTier, mode, commandText, requiresApproval, nextStep } }];
}

if (!allowedSources.has(source)) return reject('unknown_source', 'Send source="telegram-console" or source="openclaw".');
if (!allowedSpecialists.has(specialist)) return reject('unknown_specialist', 'Route to one of the registered specialist lanes.');
if (!allowedRiskTiers.has(riskTier)) return reject('unknown_risk_tier', 'Use riskTier P0, P1, or P2.');
if (mode !== 'read-only' && mode !== 'mutation') return reject('unknown_mode', 'Use mode="read-only" or mode="mutation".');
if (requiresApproval && action !== 'approve' && !approvalId) {
  return [{ json: { taskId, status: 'approval_required', source, action, specialist, riskTier, mode, commandText, requiresApproval, statusCallback, nextStep: `Founder approval required before routing ${action} to ${specialist}.` } }];
}

const normalized = commandText.toLowerCase();
let proposedWriteTool = null;
if (normalized.includes('issue')) proposedWriteTool = 'create_github_issue';
else if (normalized.includes('strategy') || normalized.includes('стратег')) proposedWriteTool = 'commit_to_strategy_doc';
else if (normalized.includes('post') || normalized.includes('topic')) proposedWriteTool = 'post_to_topic';
else if (normalized.includes('pause') || normalized.includes('deactivate') || normalized.includes('workflow')) proposedWriteTool = 'pause_workflow';
else if (normalized.includes('mute') || normalized.includes('sentry')) proposedWriteTool = 'mute_alert';

return [{ json: { taskId, status: 'accepted', source, action, specialist, riskTier, mode, commandText, requiresApproval, approvalId, statusCallback, artifacts, lane: { name: specialist, type: 'specialist-agent', execution: 'report-only-v1' }, proposedWriteTool, nextStep: `Task ${taskId} assigned to ${specialist}.` } }];
